import os
from flask import Flask, request, jsonify
import pickle
import json
from datetime import datetime, timedelta

app = Flask(__name__)

# Cache directory
CACHE_DIR = 'cache'

# Create cache directory if it doesn't exist
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_response(response, key, ttl=300):  # 5 minutes default TTL
    file_path = os.path.join(CACHE_DIR, f'{key}.pkl')
    
    with open(file_path, 'wb') as f:
        pickle.dump(response, f)
        
    metadata_file_path = os.path.join(CACHE_DIR, f'{key}_metadata.json')
    with open(metadata_file_path, 'w') as f:
        json.dump({'ttl': ttl, 'timestamp': datetime.now().isoformat()}, f)

def get_cached_response(key):
    file_path = os.path.join(CACHE_DIR, f'{key}.pkl')
    
    if not os.path.exists(file_path):
        return None
    
    with open(file_path, 'rb') as f:
        response = pickle.load(f)
        
    metadata_file_path = os.path.join(CACHE_DIR, f'{key}_metadata.json')
    
    if not os.path.exists(metadata_file_path):
        return None
    
    with open(metadata_file_path, 'r') as f:
        metadata = json.load(f)
        
    if datetime.fromisoformat(metadata['timestamp']) + timedelta(seconds=metadata['ttl']) < datetime.now():
        os.remove(file_path)
        os.remove(metadata_file_path)
        return None
        
    return response

@app.route('/api/data', methods=['GET'])
def get_data():
    key = request.args.get('key')
    
    if not key:
        return jsonify({'error': 'Missing key parameter'}), 400
    
    cached_response = get_cached_response(key)
    
    if cached_response is None:
        # Simulate expensive API call
        data = {'id': 1, 'name': 'John Doe', 'address': {'street': '123 Main St', 'city': 'Anytown'}}
        
        cache_response(data, key)
        
        return jsonify(data), 200
    
    return jsonify(cached_response), 200

if __name__ == '__main__':
    app.run(debug=True)